import os,requests
b=os.environ.get('KARAKEEP_API_ADDR','http://karakeep.lab-memory.svc.cluster.local:3000')
k=os.environ.get('KARAKEEP_API_KEY','')
s=requests.Session();s.headers['Authorization']=f'Bearer {k}'
ROOT='ipnsyy1t55vakjtzkn25y1p0';COLL='sme_salesengineer'
# --- replicate ingest.py routing ---
def fetch_lists():
  o={};c=None
  while True:
    p={'limit':100}
    if c:p['cursor']=c
    d=s.get(f'{b}/api/v1/lists',params=p,timeout=30).json()
    for L in d.get('lists',[]):o[L['id']]={'name':L.get('name'),'parentId':L.get('parentId')}
    c=d.get('nextCursor')
    if not c:return o
def members(lid):
  o=set();c=None
  while True:
    p={'limit':100}
    if c:p['cursor']=c
    d=s.get(f'{b}/api/v1/lists/{lid}/bookmarks',params=p,timeout=30).json()
    for bm in d.get('bookmarks',[]):o.add(bm['id'])
    c=d.get('nextCursor')
    if not c:return o
def kidsmap(ls):
  km={}
  for lid,m in ls.items():
    pp=m.get('parentId')
    if pp:km.setdefault(pp,[]).append(lid)
  return km
def subtree(r,km):
  out=[];st=[r]
  while st:
    n=st.pop();out.append(n);st.extend(km.get(n,[]))
  return out
def depth(lid,ls):
  dd=0;cur=ls.get(lid,{}).get('parentId')
  while cur:dd+=1;cur=ls.get(cur,{}).get('parentId')
  return dd
def resolve(ls):
  km=kidsmap(ls);best={}
  for lid in subtree(ROOT,km):
    dp=depth(lid,ls)
    for bid in members(lid):
      pv=best.get(bid)
      if pv is None or dp>pv[2]:best[bid]=(COLL,lid,dp)
  return {x:(c,l) for x,(c,l,_) in best.items()}
ls=fetch_lists()
print('LISTS:',{i:(m['name'],m['parentId']) for i,m in ls.items()})
CHILD=[i for i,m in ls.items() if m['parentId']==ROOT][0]
print('subtree of root:',subtree(ROOT,kidsmap(ls)))
print('routing (empty lists):',resolve(ls))
# prove deepest-wins: put test bookmark in the CHILD, resolve, then clean up
bid=s.get(f'{b}/api/v1/bookmarks',params={'limit':1},timeout=30).json()['bookmarks'][0]['id']
s.put(f'{b}/api/v1/lists/{CHILD}/bookmarks/{bid}',timeout=30)
r=resolve(fetch_lists())
print('routing with test bm in child:',r)
print('assigned list_id == child?', r.get(bid,(None,None))[1]==CHILD)
s.delete(f'{b}/api/v1/lists/{CHILD}/bookmarks/{bid}',timeout=30)
print('cleanup child members:',members(CHILD))

